// // This module implements a 16-bit binary down/up counter. The counter decrements or increments based on the direction signal (1 for down, 0 for up) on each clock cycle. It resets to zero when the reset signal is low. The reset signal is active low synchronous.
module up_down_counter (
	input clk,
	input reset,
	input direction,
	output reg [15:0] count);

	always @(posedge clk) begin
		if (reset)
			count <= 16'h0000;
		else if (direction)
			count <= count + 1;
		else
			count <= count - 1;
	end

endmodule
